    .btn-livre {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-annule {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      border: none;
      padding: 10px 20px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-livre:hover, .btn-annule:hover {
      transform: scale(1.02);
      filter: brightness(1.1);
    }
    
    .status-badge-detail {
      display: inline-block;
      padding: 2px 10px;
      border-radius: 15px;
      font-size: 0.7rem;
      margin-left: 8px;
    }
    
    .status-badge-detail.pending {
      background: #f59e0b;
      color: white;
    }
    
    .status-badge-detail.completed {
      background: #22c55e;
      color: white;
    }
    
    .status-badge-detail.cancelled {
      background: #ef4444;
      color: white;
    }
    
    .btn-primary {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-primary:hover {
      transform: scale(1.02);
      filter: brightness(1.1);
    }
    
    .btn-danger {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      border: none;
      padding: 8px 16px;
      border-radius: 20px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-danger:hover {
      transform: scale(1.02);
      filter: brightness(1.1);
    }
    
    @keyframes fadeIn {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    
    .animate-slide-up {
      animation: slideUp 0.3s ease-out forwards;
    }
    
    .gradient-border-box {
      position: relative;
      width: 180px;
      height: 180px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      margin-top: -60px;
      margin-left: -20px;
    }
    
    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -6px;
      z-index: -1;
      background: linear-gradient(45deg, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000);
      background-size: 450%;
      border-radius: 50%;
      animation: gradient-border 20s linear infinite;
      filter: blur(8px);
    }
    
    .cards-container {
      display: flex;
      gap: 25px;
      justify-content: center;
      margin-top: 50px;
      flex-wrap: wrap;
      position: relative;
      padding-bottom: 35px;
      z-index: 1;
      transition: transform 0.3s ease-in-out;
    }
    
    .cards-container::after {
      content: '';
      position: absolute;
      bottom: -20px;
      left: 10%;
      width: 80%;
      height: 4px;
      background: linear-gradient(90deg, transparent, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000, transparent);
      background-size: 200% 100%;
      border-radius: 4px;
      animation: rainbowLine 3s linear infinite;
      box-shadow: 0 0 20px rgba(255,0,0,0.5), 0 0 10px rgba(0,255,255,0.3);
    }
    
    .cv-card {
      flex: 1;
      min-width: 280px;
      backdrop-filter: blur(15px);
      border-radius: 35px;
      padding: 40px 30px;
      cursor: pointer;
      transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      text-align: center;
      position: relative;
      overflow: hidden;
      z-index: 5;
      animation: float 4s ease-in-out infinite;
    }
    
    .cv-card:nth-child(1) {
      background: linear-gradient(135deg, #FF6B6B 0%, #FF8E53 50%, #FF6B6B 100%);
      background-size: 200% 200%;
      box-shadow: 0 20px 40px rgba(255, 107, 107, 0.4);
      border: 1px solid rgba(255, 255, 255, 0.4);
      animation-delay: 0s;
    }
    
    .cv-card:nth-child(1):hover {
      background-position: 100% 100%;
      transform: translateY(-12px) scale(1.02);
      box-shadow: 0 30px 50px rgba(255, 107, 107, 0.6);
    }
    
    .cv-card:nth-child(2) {
      background: linear-gradient(135deg, #4ECDC4 0%, #556270 50%, #4ECDC4 100%);
      background-size: 200% 200%;
      box-shadow: 0 20px 40px rgba(78, 205, 196, 0.4);
      border: 1px solid rgba(255, 255, 255, 0.4);
      animation-delay: 0.5s;
    }
    
    .cv-card:nth-child(2):hover {
      background-position: 100% 100%;
      transform: translateY(-12px) scale(1.02);
      box-shadow: 0 30px 50px rgba(78, 205, 196, 0.6);
    }
    
    .cv-card::before {
      content: '';
      position: absolute;
      top: -50%;
      left: -50%;
      width: 200%;
      height: 200%;
      background: radial-gradient(circle, rgba(255,255,255,0.3) 0%, rgba(255,255,255,0) 70%);
      opacity: 0;
      transition: opacity 0.6s;
      pointer-events: none;
    }
    
    .cv-card:hover::before {
      opacity: 1;
      animation: shine 1.5s;
    }
    
    .btn-contact {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 12px 30px;
      border-radius: 35px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      font-size: 1rem;
    }
    
    .btn-contact:hover {
      transform: scale(1.05);
      box-shadow: 0 5px 20px rgba(34,197,94,0.4);
    }
    
    .btn-comment {
      background: linear-gradient(135deg, #ff6b6b, #f5576c);
      border: none;
      padding: 12px 30px;
      border-radius: 35px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      font-size: 1rem;
    }
    
    .btn-comment:hover {
      transform: scale(1.05);
      box-shadow: 0 5px 20px rgba(255,107,107,0.4);
    }
    
    .action-buttons {
      display: flex;
      justify-content: center;
      gap: 20px;
      margin-top: 25px;
      margin-bottom: 25px;
    }
    
    .status-badge {
      display: inline-block;
      padding: 6px 14px;
      border-radius: 25px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 12px;
    }
    
    .status-working {
      background: #22c55e;
      color: white;
    }
    
    .status-free {
      background: #ef4444;
      color: white;
    }
    
    .skill-tag {
      display: inline-block;
      padding: 5px 12px;
      background: rgba(34,197,94,0.2);
      border-radius: 18px;
      font-size: 12px;
      margin: 3px;
      color: #4ade80;
      transition: all 0.2s;
      border: 1px solid rgba(34,197,94,0.3);
    }
    
    .skill-tag:hover {
      background: rgba(34,197,94,0.35);
      transform: scale(1.05);
    }
    
    .comment-card {
      background: rgba(255,255,255,0.08);
      border-radius: 18px;
      padding: 15px;
      margin-bottom: 15px;
      transition: all 0.3s;
      border: 1px solid rgba(78,205,196,0.3);
    }
    
    .comment-card:hover {
      background: rgba(255,255,255,0.12);
      transform: translateX(8px);
    }
    
    .work-history-item {
      background: rgba(255,255,255,0.08);
      border-radius: 18px;
      padding: 15px;
      margin-bottom: 15px;
      transition: all 0.3s;
      border-left: 4px solid #22c55e;
    }
    
    .work-history-item:hover {
      background: rgba(255,255,255,0.12);
      transform: translateX(8px);
    }
    
    .rating-star {
      font-size: 32px;
      cursor: pointer;
      color: #4a4a4a;
      transition: all 0.2s;
    }
    
    .rating-star.active {
      color: #ffc107;
      text-shadow: 0 0 10px #ffc107;
    }
    
    .rating-star:hover {
      transform: scale(1.2);
    }
    
    .rating-input {
      display: flex;
      gap: 10px;
      justify-content: center;
      margin: 10px 0;
    }
    
    .place-selector {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
      gap: 12px;
      margin-top: 15px;
    }
    
    .place-option {
      background: rgba(34,197,94,0.15);
      padding: 14px;
      border-radius: 15px;
      cursor: pointer;
      text-align: center;
      transition: all 0.3s;
      border: 1px solid rgba(34,197,94,0.4);
    }
    
    .place-option:hover {
      background: rgba(34,197,94,0.3);
      transform: scale(1.02);
    }
    
    .profile-glow {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 200px;
      height: 200px;
      background: radial-gradient(circle, rgba(34,197,94,0.3) 0%, rgba(34,197,94,0) 70%);
      border-radius: 50%;
      z-index: -1;
      animation: borderPulse 2s ease-in-out infinite;
    }
    
    .bg-white-card {
      background: rgba(255, 255, 255, 0.12);
      backdrop-filter: blur(20px);
      border-radius: 40px;
      border: 1px solid rgba(255, 255, 255, 0.25);
      box-shadow: 0 25px 50px rgba(0, 0, 0, 0.2);
    }
    
    .hero-overlay {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: linear-gradient(180deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0.05) 30%, rgba(0,0,0,0) 50%, rgba(26,26,58,0.6) 100%);
    }
    
    .hero-image {
      position: absolute;
      top: 0;
      width: 100%;
      height: 100%;
      background-size: cover;
      background-position: center 40%;
      filter: brightness(0.85) contrast(1.05);
      transition: transform 0.5s ease;
    }
    
    .hero-image:hover {
      transform: scale(1.01);
    }
    
    .edit-cv-form input, .edit-cv-form textarea {
      font-size: 14px;
      transition: all 0.2s;
    }
    
    .edit-cv-form input:focus, .edit-cv-form textarea:focus {
      outline: none;
      border-color: #22c55e;
      box-shadow: 0 0 10px rgba(34,197,94,0.3);
    }
    
    @media (max-width: 768px) {
      .order-list-container {
        width: 95% !important;
        margin: 15px auto !important;
      }
      .cards-container {
        flex-direction: column;
      }
      .gradient-border-box {
        width: 130px;
        height: 130px;
        margin-top: -50px;
        margin-left: 0;
      }
      .order-detail-buttons {
        flex-direction: column;
        gap: 10px;
      }
      .order-actions {
        flex-wrap: wrap;
        justify-content: flex-end;
      }
      .action-buttons {
        flex-direction: column;
        gap: 12px;
        align-items: center;
      }
      .cards-container::after {
        width: 90%;
        left: 5%;
        bottom: -15px;
      }
      .cv-card {
        min-width: 250px;
        padding: 30px 20px;
      }
      .modal-content, .modal-content-order {
        padding: 25px;
        width: 95%;
      }
    }
  `;

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="profile-hero-section">
        <div className="shooting-stars">
          {[...Array(60)].map((_, i) => (
            <div key={i} className="star" style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              width: `${Math.random() * 3 + 1}px`,
              height: `${Math.random() * 3 + 1}px`,
              animationDelay: `${Math.random() * 5}s`,
              animationDuration: `${Math.random() * 3 + 2}s`
            }} />
          ))}
          {[...Array(10)].map((_, i) => (
            <div key={`shooting-${i}`} className="shooting-star" style={{
              left: `${Math.random() * 80 + 10}%`,
              top: `${Math.random() * 40}%`,
              width: `${Math.random() * 60 + 40}px`,
              height: '2px',
              animationDelay: `${Math.random() * 8}s`,
              animationDuration: `${Math.random() * 2 + 1.5}s`,
              transform: `rotate(${Math.random() * 60 + 30}deg)`,
              background: `linear-gradient(90deg, rgba(255,255,255,1) 0%, rgba(255,255,150,0.8) 30%, rgba(255,255,255,0) 100%)`
            }} />
          ))}
        </div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "350px", position: 'relative', overflow: 'hidden' }}>
            <div className="hero-image" style={{ 
              backgroundImage: "url('https://png.pngtree.com/thumb_back/fw800/background/20240602/pngtree-bartender-cleaning-counter-in-a-nice-pub-image_15737949.jpg')",
              backgroundSize: 'cover',
              backgroundPosition: 'center 40%'
            }}></div>
            <div className="hero-overlay"></div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white-card w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="profile-image-wrapper">
                        <div className="profile-glow"></div>
                        <div className="gradient-border-box">
                          <img alt="Jenna Stones" src="https://randomuser.me/api/portraits/women/68.jpg" className="content" style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '50%' }} />
                        </div>
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-3 lg:text-right lg:self-center"></div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-1"></div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-white">{workerInfo.name}<span className={`status-badge ${workerStatus === 'working' ? 'status-working' : 'status-free'}`}>{workerStatus === 'working' ? '✅ En poste' : '📢 En recherche'}</span></h3>
                    {workerStatus === 'working' && currentWorkPlace && (<p className="text-md text-green-400 font-semibold mt-2">📍 Travaille chez : {currentWorkPlace}</p>)}
                    <div className="text-sm leading-normal mt-2 mb-2 text-gray-400 font-bold uppercase"><i className="fas fa-map-marker-alt mr-2"></i> {workerInfo.location}</div>
                    <div className="mb-2 text-gray-300 mt-10"><i className="fas fa-briefcase mr-2 text-green-400"></i> {workerInfo.role}</div>
                  </div>
                  
                  <div className="action-buttons">
                    <button className="btn-contact" onClick={() => alert("📧 Email: jenna@example.com\n📱 Téléphone: +33 6 12 34 56 78")}>📧 Contacter</button>
                    <button className="btn-comment" onClick={() => setShowCommentsList(true)}>💬 Commenter</button>
                  </div>
                  
                  <OrderList orders={orders} onUpdateOrderStatus={updateOrderStatus} onModalOpenChange={setIsAnyModalOpen} />
                  
                  <TablesList completedOrders={completedOrders} onTableClick={(tableId) => setSelectedTableId(tableId)} />
                  
                  <div className="cards-container" style={{ transform: isAnyModalOpen || selectedTableId ? 'translateY(120px)' : 'translateY(0)', transition: 'transform 0.3s ease-in-out' }}>
                    <div className="cv-card" onClick={() => setShowWorkerCV(true)}>
                      <div className="text-6xl mb-4">📄</div>
                      <h3 className="text-xl font-bold text-white mb-2" style={{ textShadow: '2px 2px 4px rgba(0,0,0,0.2)' }}>Mon CV</h3>
                      <p className="text-white/90 text-sm">Découvrez mon parcours professionnel</p>
                      <button className="btn-primary mt-4 text-sm" style={{ padding: '6px 18px' }} onClick={(e) => { e.stopPropagation(); setShowEditCV(true); }}>✏️ Modifier CV</button>
                    </div>
                    <div className="cv-card" onClick={() => setShowManagerCV(true)}>
                      <div className="text-6xl mb-4">⭐</div>
                      <h3 className="text-xl font-bold text-white mb-2" style={{ textShadow: '2px 2px 4px rgba(0,0,0,0.2)' }}>Évaluations</h3>
                      <p className="text-white/90 text-sm">Historique et retours des managers</p>
                    </div>
                  </div>
                  
                  <div className="mt-10 py-10 border-t border-white/20 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-200 italic">"{workerInfo.bio}"</p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {workerInfo.skills.map((skill, i) => (
                            <span key={i} className="skill-tag">{skill}</span>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {selectedTableId && selectedTable && (
        <TableDetailModal 
          table={selectedTable} 
          onLiberateTable={(tableId) => { liberateTable(tableId); setSelectedTableId(null); }}
          onClose={() => setSelectedTableId(null)} 
        />
      )}
      
      {/* مودال عرض التعليقات */}
      {showCommentsList && (<div className="modal-overlay" onClick={() => setShowCommentsList(false)}><div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '550px', width: '90%' }}><button onClick={() => setShowCommentsList(false)} className="close-btn">✕</button><div className="text-center"><div className="text-6xl mb-4">💬</div><h2 className="text-2xl font-bold text-white mb-2">Commentaires</h2><button onClick={() => setShowAddComment(true)} className="btn-primary w-full mb-6">✏️ Écrire un commentaire</button><div className="mt-4"><h3 className="text-lg font-semibold text-white mb-3 text-left">📖 Commentaires récents ({comments.length})</h3>{comments.map((comment) => (<div key={comment.id} className="comment-card"><div className="flex justify-between items-start flex-wrap mb-2"><div><h4 className="text-white font-bold">{comment.author}</h4><p className="text-gray-400 text-xs">{comment.date}</p></div><div className="stars">{[...Array(5)].map((_, i) => (<span key={i} style={{ color: i < comment.rating ? '#ffc107' : '#4a4a4a', fontSize: '16px' }}>★</span>))}</div></div><p className="text-gray-300 text-sm mt-2">{comment.text}</p></div>))}</div></div></div></div>)}
      
      {/* مودال إضافة تعليق */}
      {showAddComment && (<div className="modal-overlay" onClick={() => setShowAddComment(false)}><div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '550px', width: '90%' }}><button onClick={() => setShowAddComment(false)} className="close-btn">✕</button><div><div className="text-center"><div className="text-6xl mb-4">✏️</div><h2 className="text-2xl font-bold text-white mb-2">Nouveau commentaire</h2></div><div className="mt-4"><label className="text-white text-sm block mb-2">👤 Votre nom</label><input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={newComment.author} onChange={(e) => setNewComment({...newComment, author: e.target.value})} placeholder="Entrez votre nom" /></div><div className="mt-3"><label className="text-white text-sm block mb-2">⭐ Note (1-5)</label><div className="rating-input">{[1,2,3,4,5].map(star => (<span key={star} className={`rating-star ${newComment.rating >= star ? 'active' : ''}`} onClick={() => setNewComment({...newComment, rating: star})}>★</span>))}</div></div><div className="mt-3"><label className="text-white text-sm block mb-2">💬 Votre commentaire</label><textarea className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" rows="4" value={newComment.text} onChange={(e) => setNewComment({...newComment, text: e.target.value})} placeholder="Écrivez votre commentaire ici..."></textarea></div><button onClick={addComment} className="btn-primary w-full mt-4">📤 Publier le commentaire</button></div></div></div>)}
      
      {/* مودال عرض CV */}
      {showWorkerCV && (<div className="modal-overlay" onClick={() => setShowWorkerCV(false)}><div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '550px', width: '90%' }}><button onClick={() => setShowWorkerCV(false)} className="close-btn">✕</button><div style={{ textAlign: 'center' }}><div className="text-6xl mb-4">👩‍💻</div><h2 className="text-2xl font-bold text-white mb-2">{workerInfo.name}</h2><p className="text-green-400 mb-4">{workerInfo.role}</p><div className="text-left"><h3 className="text-xl font-bold text-white mt-4 mb-2">📋 Profil</h3><p className="text-gray-300">{workerInfo.bio}</p><h3 className="text-xl font-bold text-white mt-4 mb-2">💪 Compétences</h3><div className="flex flex-wrap gap-2">{workerInfo.skills.map((skill, i) => (<span key={i} className="skill-tag">{skill}</span>))}</div><h3 className="text-xl font-bold text-white mt-4 mb-2">📞 Contact</h3><p className="text-gray-300">📧 {workerInfo.email}</p><p className="text-gray-300">📱 {workerInfo.phone}</p></div><button onClick={() => { setShowWorkerCV(false); setShowEditCV(true); }} className="btn-primary w-full mt-4">✏️ Modifier CV</button></div></div></div>)}
      
      {showEditCV && <EditCVModal workerInfo={workerInfo} onSave={saveCVChanges} onClose={() => setShowEditCV(false)} />}
      
      {/* مودال إدارة التقييمات */}
      {showManagerCV && (<div className="modal-overlay" onClick={() => setShowManagerCV(false)}><div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '600px', width: '90%' }}><button onClick={() => setShowManagerCV(false)} className="close-btn">✕</button><div><div className="text-center"><div className="text-6xl mb-4">⭐</div><h2 className="text-2xl font-bold text-white mb-2">Gestion des évaluations</h2></div><div style={{ background: 'rgba(34,197,94,0.1)', borderRadius: '20px', padding: '20px', marginBottom: '20px' }}><h3 className="text-lg font-bold text-green-400 mb-3">👨‍💼 Panel Manager</h3><div className="flex gap-3 flex-wrap mb-4">{workerStatus !== 'working' && <button onClick={() => setShowPlaceSelector(true)} className="btn-primary">✅ Activer</button>}{workerStatus === 'working' && <button onClick={deactivateWorker} className="btn-danger">🚫 Terminer</button>}</div>{showPlaceSelector && (<div className="place-selector">{availablePlaces.map(place => (<div key={place.id} className="place-option" onClick={() => changeWorkPlace(place)}><div className="text-2xl">{place.icon}</div><div className="text-white font-bold text-sm">{place.name}</div></div>))}</div>)}<div className="mt-3"><label className="text-white text-sm">⭐ Note (1-5)</label><div className="rating-input">{[1,2,3,4,5].map(star => (<span key={star} className={`rating-star ${currentRating >= star ? 'active' : ''}`} onClick={() => setCurrentRating(star)}>★</span>))}</div></div><div className="mt-3"><label className="text-white text-sm">💬 Commentaire</label><textarea className="w-full p-2 rounded-lg mt-1 bg-white/10 text-white" rows="3" value={managerComment} onChange={(e) => setManagerComment(e.target.value)} placeholder="Écrivez votre commentaire..."></textarea></div><button onClick={addManagerReview} className="btn-primary w-full mt-3">✅ Ajouter</button></div><h3 className="text-lg font-bold text-white mb-3">📋 Historique</h3>{workHistory.map((work, index) => (<div key={index} className="work-history-item"><div className="flex justify-between items-center flex-wrap"><h4 className="text-white font-bold">{work.place}</h4><div className="stars">{[...Array(5)].map((_, i) => (<span key={i} style={{ color: i < work.rating ? '#ffc107' : '#4a4a4a', fontSize: '16px' }}>★</span>))}</div></div><p className="text-gray-300 text-sm">{work.role} • {work.duration}</p><p className="text-gray-400 text-sm mt-2">"{work.review}"</p></div>))}</div></div></div>)}
      
      <Footer />
    </>
  );
}
